package ru.memearena.scout; import org.junit.jupiter.api.Test; import ru.memearena.scout.domain.ScoutRank; import static org.assertj.core.api.Assertions.assertThat; class ScoutPoliciesTest{ @Test void rankThresholds(){ assertThat(ScoutRank.fromPoints(0)).isEqualTo(ScoutRank.OBSERVER); assertThat(ScoutRank.fromPoints(100)).isEqualTo(ScoutRank.SCOUT); assertThat(ScoutRank.fromPoints(500)).isEqualTo(ScoutRank.TREND_HUNTER); assertThat(ScoutRank.fromPoints(1500)).isEqualTo(ScoutRank.MEME_ORACLE); }}
